class RobustGrader:
    def grade(self, question, ground_truth, answer, tool_trace):
        # Check for known gaming patterns first
        for pattern in self.violation_patterns:
            if pattern.matches(answer, tool_trace):
                return {'score': 0.0, 'violation': True}

        # Multi-criteria evaluation
        scores = {
            'correctness': self._check_correctness(answer, ground_truth),
            'reasoning': self._check_reasoning_quality(tool_trace),
            'completeness': self._check_completeness(answer),
            'citations': self._check_citations(answer, tool_trace)
        }

        weights = {'correctness': 0.5, 'reasoning': 0.2,
                   'completeness': 0.2, 'citations': 0.1}
        return {'score': sum(w * scores[k] for k, w in weights.items())}
